INSERT INTO labs (
  module_id, title, slug, objective, prerequisites, difficulty, estimated_minutes,
  azure_services, useful_commands, common_pitfalls, understanding_goals, verification_steps
) VALUES
((SELECT id FROM modules WHERE name = 'Identites et gouvernance'), 'Creer un Resource Group avec tags', 'resource-group-tags',
'Creer un groupe de ressources propre, tague et pret a recevoir les ressources des labs.',
'Azure CLI connecte avec az login, une subscription selectionnee, convention de nommage rg-az104-<usage>.',
'debutant', 25, ARRAY['Resource Groups','Tags'],
'[{"label":"Creer le RG","command":"az group create --name rg-az104-core --location canadacentral --tags env=lab owner=az104 costCenter=training"},{"label":"Lister les tags","command":"az group show --name rg-az104-core --query tags"}]'::jsonb,
ARRAY['Oublier de selectionner la bonne subscription','Utiliser une region differente des ressources prevues','Creer des tags incoherents qui compliquent les rapports de cout'],
ARRAY['Un resource group est un conteneur logique, pas une limite reseau','Les tags aident a gouverner les couts et l ownership','Les ressources heritent rarement automatiquement de tous les tags du RG'],
ARRAY['az group show retourne le RG dans la bonne region','Les tags env, owner et costCenter sont presents','Le portail affiche le meme groupe de ressources']),
