'Un resource group existant et un utilisateur ou groupe Entra ID de test.',
'intermediaire', 40, ARRAY['Azure RBAC','Microsoft Entra ID'],
'[{"label":"Role Reader","command":"az role assignment create --assignee <objectId> --role Reader --resource-group rg-az104-core"},{"label":"Verifier RBAC","command":"az role assignment list --resource-group rg-az104-core --output table"}]'::jsonb,
ARRAY['Assigner Contributor quand Reader suffit','Confondre appId, user principal name et objectId','Tester trop vite avant la propagation RBAC'],
ARRAY['RBAC s applique a un scope precis','Les roles built-in couvrent des permissions differentes','La propagation peut prendre plusieurs minutes'],
ARRAY['L affectation apparait avec le bon principal','Le scope est /resourceGroups/rg-az104-core','Le compte teste ne peut pas modifier si seul Reader est donne']),
((SELECT id FROM modules WHERE name = 'Stockage Azure'), 'Creer un Storage Account securise', 'secure-storage-account',
