'[{"label":"Creer le storage","command":"az storage account create -g rg-az104-storage -n <uniquestorage> -l canadacentral --sku Standard_LRS --kind StorageV2 --https-only true --min-tls-version TLS1_2"},{"label":"Desactiver public access","command":"az storage account update -g rg-az104-storage -n <uniquestorage> --allow-blob-public-access false"}]'::jsonb,
ARRAY['Nom non unique ou avec caracteres invalides','Laisser l acces public blob active par defaut','Confondre replication LRS, ZRS et GRS'],
