ARRAY['Le compte existe en StorageV2','allowBlobPublicAccess est false','Minimum TLS affiche TLS1_2']),
((SELECT id FROM modules WHERE name = 'Stockage Azure'), 'Creer un File Share Azure', 'azure-file-share',
