INSERT INTO lab_steps (lab_id, step_order, title, instruction, command_hint) VALUES
((SELECT id FROM labs WHERE slug='resource-group-tags'),1,'Selectionner la subscription','Liste les subscriptions et selectionne celle reservee a tes labs pour eviter de creer des ressources au mauvais endroit.','az account list -o table && az account set --subscription <subscriptionId>'),
((SELECT id FROM labs WHERE slug='resource-group-tags'),2,'Creer le resource group','Cree le groupe de ressources avec une region coherente et les tags minimaux env, owner et costCenter.','az group create --name rg-az104-core --location canadacentral --tags env=lab owner=az104 costCenter=training'),
((SELECT id FROM labs WHERE slug='resource-group-tags'),3,'Verifier et corriger les tags','Affiche le groupe de ressources, verifie les tags, puis ajoute un tag purpose si besoin.','az group update --name rg-az104-core --set tags.purpose=practice'),
((SELECT id FROM labs WHERE slug='rbac-resource-group'),1,'Identifier le principal','Recupere l objectId du groupe ou utilisateur qui recevra le role.','az ad group show --group az104-operators --query id -o tsv'),
((SELECT id FROM labs WHERE slug='rbac-resource-group'),2,'Assigner le role minimal','Assigne Reader au scope du resource group, pas a la subscription.','az role assignment create --assignee <objectId> --role Reader --resource-group rg-az104-core'),
((SELECT id FROM labs WHERE slug='rbac-resource-group'),3,'Tester les limites','Connecte-toi ou simule le principal et confirme qu il peut lire mais pas modifier les ressources.','az role assignment list --resource-group rg-az104-core -o table'),
((SELECT id FROM labs WHERE slug='secure-storage-account'),1,'Preparer le nom','Choisis un nom unique de 3 a 24 caracteres en minuscules sans tirets.',''),
((SELECT id FROM labs WHERE slug='secure-storage-account'),2,'Creer le compte securise','Cree le compte avec HTTPS obligatoire et TLS 1.2 minimum.','az storage account create -g rg-az104-storage -n <uniquestorage> -l canadacentral --sku Standard_LRS --kind StorageV2 --https-only true --min-tls-version TLS1_2'),
((SELECT id FROM labs WHERE slug='secure-storage-account'),3,'Durcir l acces public','Desactive l acces public blob et verifie la configuration finale.','az storage account update -g rg-az104-storage -n <uniquestorage> --allow-blob-public-access false'),
((SELECT id FROM labs WHERE slug='azure-file-share'),1,'Creer le partage','Cree un share Azure Files avec quota limite pour le lab.','az storage share-rm create --resource-group rg-az104-storage --storage-account <uniquestorage> --name az104share --quota 5'),
((SELECT id FROM labs WHERE slug='azure-file-share'),2,'Ajouter un fichier test','Charge ou cree un petit fichier pour confirmer que le share est utilisable.','az storage file upload --account-name <uniquestorage> --share-name az104share --source .\\test.txt --path test.txt'),
((SELECT id FROM labs WHERE slug='azure-file-share'),3,'Verifier les limites reseau','Determine si ton reseau autorise SMB 445 ou si tu dois tester depuis Azure.','Test-NetConnection <storage>.file.core.windows.net -Port 445'),
((SELECT id FROM labs WHERE slug='windows-vm-basic'),1,'Creer la VM','Deploie Windows Server avec une taille economique pour le lab.','az vm create -g rg-az104-vm -n vm-az104-win --image Win2022Datacenter --admin-username azureadmin --admin-password <StrongPassword> --size Standard_B2s'),
((SELECT id FROM labs WHERE slug='windows-vm-basic'),2,'Limiter RDP','Ouvre RDP uniquement depuis ton IP publique actuelle.','az vm open-port -g rg-az104-vm -n vm-az104-win --port 3389 --source-address-prefixes <yourPublicIp>/32'),
((SELECT id FROM labs WHERE slug='windows-vm-basic'),3,'Valider l etat','Verifie l etat power/provisioning et recupere l IP publique.','az vm get-instance-view -g rg-az104-vm -n vm-az104-win --query instanceView.statuses'),
((SELECT id FROM labs WHERE slug='linux-vm-basic'),1,'Creer la VM','Deploie Ubuntu avec une cle SSH generee automatiquement.','az vm create -g rg-az104-vm -n vm-az104-linux --image Ubuntu2204 --admin-username azureuser --generate-ssh-keys --size Standard_B1s'),
((SELECT id FROM labs WHERE slug='linux-vm-basic'),2,'Installer un service','Connecte-toi en SSH et installe nginx pour avoir une verification simple.','sudo apt-get update && sudo apt-get install -y nginx'),
((SELECT id FROM labs WHERE slug='linux-vm-basic'),3,'Ouvrir HTTP','Autorise HTTP dans le NSG et teste depuis le navigateur.','az vm open-port -g rg-az104-vm -n vm-az104-linux --port 80'),
((SELECT id FROM labs WHERE slug='configure-nsg'),1,'Creer le NSG','Cree un NSG dedie au trafic web.','az network nsg create -g rg-az104-network -n nsg-az104-web'),
((SELECT id FROM labs WHERE slug='configure-nsg'),2,'Ajouter une regle','Ajoute une regle Allow HTTP avec une priorite explicite.','az network nsg rule create -g rg-az104-network --nsg-name nsg-az104-web -n Allow-HTTP --priority 200 --access Allow --protocol Tcp --direction Inbound --destination-port-ranges 80'),
((SELECT id FROM labs WHERE slug='configure-nsg'),3,'Associer et tester','Associe le NSG au subnet ou a la NIC puis teste le flux attendu.','az network vnet subnet update -g rg-az104-network --vnet-name vnet-az104 -n snet-web --network-security-group nsg-az104-web'),
((SELECT id FROM labs WHERE slug='vnet-subnet-basic'),1,'Dessiner le plan IP','Note l espace VNet et les subnets avant de creer les ressources.',''),
((SELECT id FROM labs WHERE slug='vnet-subnet-basic'),2,'Creer VNet et subnet web','Cree le VNet avec un premier subnet web.','az network vnet create -g rg-az104-network -n vnet-az104 -l canadacentral --address-prefix 10.10.0.0/16 --subnet-name snet-web --subnet-prefix 10.10.1.0/24'),
((SELECT id FROM labs WHERE slug='vnet-subnet-basic'),3,'Ajouter subnet data','Ajoute un deuxieme subnet reserve aux donnees.','az network vnet subnet create -g rg-az104-network --vnet-name vnet-az104 -n snet-data --address-prefixes 10.10.2.0/24'),
((SELECT id FROM labs WHERE slug='vnet-peering'),1,'Creer deux VNets','Cree vnet-a et vnet-b avec des CIDR non chevauchants.','az network vnet create -g rg-az104-network -n vnet-a --address-prefix 10.20.0.0/16 --subnet-name default --subnet-prefix 10.20.1.0/24'),
((SELECT id FROM labs WHERE slug='vnet-peering'),2,'Creer les peerings','Cree le peering dans les deux directions pour obtenir Connected.','az network vnet peering create -g rg-az104-network -n peer-a-to-b --vnet-name vnet-a --remote-vnet vnet-b --allow-vnet-access'),
((SELECT id FROM labs WHERE slug='vnet-peering'),3,'Tester la connectivite','Teste une connexion par IP privee entre deux VMs ou verifie les effective routes.','az network vnet peering list -g rg-az104-network --vnet-name vnet-a -o table'),
((SELECT id FROM labs WHERE slug='azure-bastion-basic'),1,'Creer le subnet Bastion','Ajoute AzureBastionSubnet avec un prefix /26 ou plus grand.','az network vnet subnet create -g rg-az104-network --vnet-name vnet-az104 -n AzureBastionSubnet --address-prefixes 10.10.250.0/26'),
((SELECT id FROM labs WHERE slug='azure-bastion-basic'),2,'Deployer Bastion','Cree l IP publique Standard puis la ressource Bastion.','az network bastion create -g rg-az104-network -n bastion-az104 --public-ip-address pip-bastion --vnet-name vnet-az104 --location canadacentral'),
((SELECT id FROM labs WHERE slug='azure-bastion-basic'),3,'Retirer l IP publique VM','Verifie que la VM peut etre administree sans IP publique directe.','az network nic ip-config update --ids <ipConfigId> --remove publicIpAddress'),
((SELECT id FROM labs WHERE slug='vm-backup-create'),1,'Creer le vault','Cree un Recovery Services Vault dans la meme region que la VM.','az backup vault create -g rg-az104-backup -n rsv-az104 -l canadacentral'),
((SELECT id FROM labs WHERE slug='vm-backup-create'),2,'Activer la protection','Attache la policy DefaultPolicy a la VM de test.','az backup protection enable-for-vm -g rg-az104-backup --vault-name rsv-az104 --vm vm-az104-linux --policy-name DefaultPolicy'),
((SELECT id FROM labs WHERE slug='vm-backup-create'),3,'Surveiller le job','Liste les jobs et confirme que la sauvegarde initiale demarre.','az backup job list -g rg-az104-backup --vault-name rsv-az104 -o table'),
((SELECT id FROM labs WHERE slug='vm-restore'),1,'Lister les items proteges','Trouve le container et l item de la VM sauvegardee.','az backup item list -g rg-az104-backup --vault-name rsv-az104 --backup-management-type AzureIaasVM --workload-type VM -o table'),
((SELECT id FROM labs WHERE slug='vm-restore'),2,'Choisir un point','Liste les recovery points et choisis le plus recent valide.','az backup recoverypoint list -g rg-az104-backup --vault-name rsv-az104 --container-name <container> --item-name <item> --backup-management-type AzureIaasVM --workload-type VM'),
((SELECT id FROM labs WHERE slug='vm-restore'),3,'Restaurer les disques','Lance une restauration de disques dans un RG de test et suis le job.','az backup restore restore-disks -g rg-az104-backup --vault-name rsv-az104 --container-name <container> --item-name <item> --rp-name <rpName> --storage-account <storage>'),
((SELECT id FROM labs WHERE slug='azure-monitor-alert'),1,'Creer action group','Cree un groupe d action avec un email que tu peux confirmer.','az monitor action-group create -g rg-az104-monitor -n ag-az104 --short-name az104 --action email admin az104@example.com'),
((SELECT id FROM labs WHERE slug='azure-monitor-alert'),2,'Creer alerte metrique','Cree une alerte CPU sur la VM avec seuil de test.','az monitor metrics alert create -g rg-az104-monitor -n vm-cpu-high --scopes <vmResourceId> --condition "avg Percentage CPU > 80" --window-size 5m --evaluation-frequency 1m --action ag-az104'),
((SELECT id FROM labs WHERE slug='azure-monitor-alert'),3,'Declencher ou simuler','Genere de la charge ou abaisse temporairement le seuil pour observer l etat.','az monitor metrics alert show -g rg-az104-monitor -n vm-cpu-high'),
((SELECT id FROM labs WHERE slug='log-analytics-workspace'),1,'Creer workspace','Cree un workspace Log Analytics pour les labs monitoring.','az monitor log-analytics workspace create -g rg-az104-monitor -n law-az104 -l canadacentral'),
((SELECT id FROM labs WHERE slug='log-analytics-workspace'),2,'Noter les identifiants','Recupere customerId et resourceId pour les diagnostics.','az monitor log-analytics workspace show -g rg-az104-monitor -n law-az104'),
((SELECT id FROM labs WHERE slug='log-analytics-workspace'),3,'Executer une requete','Teste une requete KQL simple une fois des donnees envoyees.','az monitor log-analytics query -w <workspaceId> --analytics-query "AzureActivity | take 5"'),
((SELECT id FROM labs WHERE slug='diagnostic-settings'),1,'Identifier la ressource','Recupere le resourceId de la ressource a surveiller et celui du workspace.','az resource show -g <rg> -n <name> --resource-type <type> --query id -o tsv'),
((SELECT id FROM labs WHERE slug='diagnostic-settings'),2,'Creer le setting','Active logs et metriques disponibles vers Log Analytics.','az monitor diagnostic-settings create --name diag-az104 --resource <resourceId> --workspace <workspaceResourceId> --metrics "[{category:AllMetrics,enabled:true}]"'),
((SELECT id FROM labs WHERE slug='diagnostic-settings'),3,'Verifier ingestion','Attends quelques minutes puis confirme que les tables recoivent des donnees.','az monitor diagnostic-settings list --resource <resourceId>'),
((SELECT id FROM labs WHERE slug='managed-identity'),1,'Activer identity','Active une system-assigned managed identity sur la VM.','az vm identity assign -g rg-az104-vm -n vm-az104-linux'),
((SELECT id FROM labs WHERE slug='managed-identity'),2,'Donner un role','Assigne un role minimal a l identity sur la ressource cible.','az role assignment create --assignee <principalId> --role "Storage Blob Data Reader" --scope <storageResourceId>'),
((SELECT id FROM labs WHERE slug='managed-identity'),3,'Tester depuis la VM','Depuis la VM, demande un token a IMDS et teste l acces.','curl -H Metadata:true "http://169.254.169.254/metadata/identity/oauth2/token?api-version=2018-02-01&resource=https://storage.azure.com/"'),
((SELECT id FROM labs WHERE slug='key-vault-basics'),1,'Creer le vault','Cree un Key Vault en mode RBAC.','az keyvault create -g rg-az104-sec -n <uniqueVaultName> -l canadacentral --enable-rbac-authorization true'),
((SELECT id FROM labs WHERE slug='key-vault-basics'),2,'Ajouter un secret','Stocke un secret de demo non sensible.','az keyvault secret set --vault-name <uniqueVaultName> -n demo-secret --value "ChangeMe123!"'),
((SELECT id FROM labs WHERE slug='key-vault-basics'),3,'Tester l acces','Lis le secret avec un principal autorise, puis observe le refus avec un principal non autorise.','az keyvault secret show --vault-name <uniqueVaultName> -n demo-secret'),
((SELECT id FROM labs WHERE slug='azure-policy-tags'),1,'Choisir la definition','Trouve une definition built-in liee aux tags.','az policy definition list --query "[?contains(displayName, ''tag'')].[displayName,name]" -o table'),
((SELECT id FROM labs WHERE slug='azure-policy-tags'),2,'Assigner au scope de test','Assigne la policy au RG ou a la subscription de lab.','az policy assignment create --name require-env-tag --policy <definitionName> --scope <scope>'),
((SELECT id FROM labs WHERE slug='azure-policy-tags'),3,'Tester la conformite','Cree une ressource avec et sans tag pour comprendre l effet.','az policy state list --resource-group rg-az104-core -o table'),
((SELECT id FROM labs WHERE slug='entra-id-groups'),1,'Creer le groupe','Cree un groupe de securite pour les operateurs AZ-104.','az ad group create --display-name az104-operators --mail-nickname az104-operators'),
((SELECT id FROM labs WHERE slug='entra-id-groups'),2,'Ajouter un membre','Ajoute un utilisateur test via son objectId.','az ad group member add --group az104-operators --member-id <userObjectId>'),
((SELECT id FROM labs WHERE slug='entra-id-groups'),3,'Utiliser le groupe','Utilise le groupe dans une affectation RBAC de lab.','az role assignment create --assignee <groupObjectId> --role Reader --resource-group rg-az104-core'),
((SELECT id FROM labs WHERE slug='mfa-conditional-access-concepts'),1,'Definir le scenario','Ecris qui est cible, quelles apps sont protegees, et quels risques declenchent MFA.',''),
((SELECT id FROM labs WHERE slug='mfa-conditional-access-concepts'),2,'Prevoir les exclusions','Documente le compte break-glass, les exclusions et la surveillance associee.',''),
((SELECT id FROM labs WHERE slug='mfa-conditional-access-concepts'),3,'Valider en report-only','Explique comment tu testerais la policy en report-only avant enforcement.','az rest --method GET --uri https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies'),
((SELECT id FROM labs WHERE slug='blob-lifecycle-management'),1,'Creer des blobs test','Cree un container logs et charge quelques fichiers de test.','az storage container create --account-name <storage> --name logs --auth-mode login'),
((SELECT id FROM labs WHERE slug='blob-lifecycle-management'),2,'Rediger policy JSON','Prepare une regle qui deplace les blobs logs vers cool apres quelques jours.',''),
((SELECT id FROM labs WHERE slug='blob-lifecycle-management'),3,'Appliquer et verifier','Applique la policy et relis-la depuis Azure.','az storage account management-policy show -g rg-az104-storage --account-name <storage>'),
((SELECT id FROM labs WHERE slug='vm-custom-script-extension'),1,'Preparer le script','Rends le script idempotent: il peut etre relance sans erreur bloquante.',''),
((SELECT id FROM labs WHERE slug='vm-custom-script-extension'),2,'Executer l extension','Lance Custom Script Extension sur la VM cible.','az vm extension set -g rg-az104-vm --vm-name vm-az104-linux --name customScript --publisher Microsoft.Azure.Extensions --settings ''{"commandToExecute":"sudo apt-get update && sudo apt-get install -y nginx"}'''),
((SELECT id FROM labs WHERE slug='vm-custom-script-extension'),3,'Lire le resultat','Verifie le provisioning state et les logs extension si necessaire.','az vm extension show -g rg-az104-vm --vm-name vm-az104-linux -n customScript');

INSERT INTO user_lab_progress (lab_id, status, completed_step_ids, personal_notes)
SELECT id,
  CASE WHEN slug IN ('resource-group-tags','linux-vm-basic','azure-monitor-alert') THEN 'in_progress' ELSE 'not_started' END,
  CASE
    WHEN slug = 'resource-group-tags' THEN ARRAY[(SELECT id FROM lab_steps WHERE lab_id = labs.id AND step_order = 1)]
    WHEN slug = 'linux-vm-basic' THEN ARRAY[(SELECT id FROM lab_steps WHERE lab_id = labs.id AND step_order = 1)]
    WHEN slug = 'azure-monitor-alert' THEN ARRAY[(SELECT id FROM lab_steps WHERE lab_id = labs.id AND step_order = 1)]
    ELSE ARRAY[]::INTEGER[]
  END,
  CASE WHEN slug = 'resource-group-tags' THEN 'Penser a standardiser les tags avant les prochains labs.' ELSE '' END
FROM labs;

INSERT INTO quiz_questions (module_id, question, choices, correct_answer, explanation, difficulty) VALUES
((SELECT id FROM modules WHERE name = 'Identites et gouvernance'), 'Quel scope RBAC est le plus restrictif pour donner acces a une equipe sur un seul groupe de ressources ?', '["Subscription","Management group","Resource group","Tenant root group"]', 2, 'Le scope resource group limite les permissions aux ressources contenues dans ce groupe.', 'debutant'),
((SELECT id FROM modules WHERE name = 'Stockage Azure'), 'Quel container est utilise par le site web statique d''un compte de stockage ?', '["$root","$logs","$web","static"]', 2, 'Azure Storage utilise le container special $web pour le contenu statique.', 'intermediaire'),
((SELECT id FROM modules WHERE name = 'Machines virtuelles'), 'Quel mecanisme injecte une configuration au premier demarrage d''une VM Linux ?', '["cloud-init","Azure Policy","Managed Identity","VNet peering"]', 0, 'cloud-init execute une configuration initiale pendant le provisioning Linux.', 'intermediaire'),
((SELECT id FROM modules WHERE name = 'Reseau virtuel'), 'Quel composant filtre le trafic reseau au niveau subnet ou NIC ?', '["NSG","Route table uniquement","Recovery vault","Log Analytics workspace"]', 0, 'Un Network Security Group applique des regles entrantes et sortantes.', 'debutant'),
((SELECT id FROM modules WHERE name = 'Monitoring'), 'Ou stocke-t-on les requetes KQL et journaux collectes pour analyse ?', '["Log Analytics workspace","Storage queue","Azure Files","Key Vault"]', 0, 'Log Analytics centralise les logs Azure Monitor et permet les requetes KQL.', 'intermediaire'),
((SELECT id FROM modules WHERE name = 'Backup et Recovery'), 'Quel service protege les workloads par politiques de sauvegarde ?', '["Azure Backup","Azure Front Door","Azure Bastion","Azure Firewall"]', 0, 'Azure Backup utilise des vaults et politiques pour proteger les workloads.', 'debutant'),
((SELECT id FROM modules WHERE name = 'Securite et RBAC'), 'Quel principe recommande d''attribuer uniquement les permissions necessaires ?', '["Defense in depth","Least privilege","Hot path","Eventual consistency"]', 1, 'Le least privilege reduit la surface de risque en limitant les droits.', 'debutant');

INSERT INTO notes (module_id, title, content, tags) VALUES
((SELECT id FROM modules WHERE name = 'Securite et RBAC'), 'RBAC scopes', 'Ordre des scopes: management group > subscription > resource group > resource. Toujours choisir le scope le plus bas possible.', ARRAY['rbac','gouvernance']),
((SELECT id FROM modules WHERE name = 'Machines virtuelles'), 'Commandes VM utiles', 'az vm list-ip-addresses -g <rg> -n <vm> -o table\naz vm get-instance-view -g <rg> -n <vm> --query instanceView.statuses', ARRAY['vm','cli']),
((SELECT id FROM modules WHERE name = 'Monitoring'), 'KQL depart rapide', 'AzureActivity | summarize count() by OperationNameValue | order by count_ desc', ARRAY['monitoring','kql']);

